1	// Copyright 2020 ETH Zurich and University of Bologna.
2	// Copyright and related rights are licensed under the Solderpad Hardware
3	// License, Version 0.51 (the "License"); you may not use this file except in
4	// compliance with the License.  You may obtain a copy of the License at
5	// http://solderpad.org/licenses/SHL-0.51. Unless required by applicable law
6	// or agreed to in writing, software, hardware and materials distributed under
7	// this License is distributed on an "AS IS" BASIS, WITHOUT WARRANTIES OR
8	// CONDITIONS OF ANY KIND, either express or implied. See the License for the
9	// specific language governing permissions and limitations under the License.
10	//
11	// Authors:
12	// - Matheus Cavalcante <matheusd@iis.ee.ethz.ch>
13	
14	// Description:
15	// Data width downsize conversion.
16	// Connects a wide master to a narrower slave.
17	
18	// NOTE: The downsizer does not support WRAP bursts, and will answer with SLVERR
19	// upon receiving a burst of such type.  The downsizer does support FIXED
20	// bursts, but only if they consist of a single beat; it will answer with SLVERR
21	// on multi-beat FIXED bursts.
22	module axi_dw_downsizer #(
23	    parameter int unsigned AxiMaxReads         = 1    , // Number of outstanding reads
24	    parameter int unsigned AxiSlvPortDataWidth = 8    , // Data width of the slv port
25	    parameter int unsigned AxiMstPortDataWidth = 8    , // Data width of the mst port
26	    parameter int unsigned AxiAddrWidth        = 1    , // Address width
27	    parameter int unsigned AxiIdWidth          = 1    , // ID width
28	    parameter type aw_chan_t                   = logic, // AW Channel Type
29	    parameter type mst_w_chan_t                = logic, //  W Channel Type for mst port
30	    parameter type slv_w_chan_t                = logic, //  W Channel Type for slv port
31	    parameter type b_chan_t                    = logic, //  B Channel Type
32	    parameter type ar_chan_t                   = logic, // AR Channel Type
33	    parameter type mst_r_chan_t                = logic, //  R Channel Type for mst port
34	    parameter type slv_r_chan_t                = logic, //  R Channel Type for slv port
35	    parameter type axi_mst_req_t               = logic, // AXI Request Type for mst ports
36	    parameter type axi_mst_resp_t              = logic, // AXI Response Type for mst ports
37	    parameter type axi_slv_req_t               = logic, // AXI Request Type for slv ports
38	    parameter type axi_slv_resp_t              = logic  // AXI Response Type for slv ports
39	  ) (
40	    input  logic          clk_i,
41	    input  logic          rst_ni,
42	    // Slave interface
43	    input  axi_slv_req_t  slv_req_i,
44	    output axi_slv_resp_t slv_resp_o,
45	    // Master interface
46	    output axi_mst_req_t  mst_req_o,
47	    input  axi_mst_resp_t mst_resp_i
48	  );
49	
50	  /*****************
51	   *  DEFINITIONS  *
52	   *****************/
53	  import axi_pkg::aligned_addr;
54	  import axi_pkg::modifiable  ;
55	
56	  import cf_math_pkg::idx_width;
57	
58	  // Type used to index which adapter is handling each outstanding transaction.
59	  localparam TranIdWidth = AxiMaxReads > 1 ? $clog2(AxiMaxReads) : 1;
60	  typedef logic [TranIdWidth-1:0] tran_id_t;
61	
62	  // Data width
63	  localparam AxiSlvPortStrbWidth = AxiSlvPortDataWidth / 8;
64	  localparam AxiMstPortStrbWidth = AxiMstPortDataWidth / 8;
65	
66	  localparam AxiSlvPortMaxSize = $clog2(AxiSlvPortStrbWidth);
67	  localparam AxiMstPortMaxSize = $clog2(AxiMstPortStrbWidth);
68	
69	  localparam SlvPortByteMask = AxiSlvPortStrbWidth - 1;
70	  localparam MstPortByteMask = AxiMstPortStrbWidth - 1;
71	
72	  // Byte-grouped data words
73	  typedef logic [AxiMstPortStrbWidth-1:0][7:0] mst_data_t;
74	  typedef logic [AxiSlvPortStrbWidth-1:0][7:0] slv_data_t;
75	
76	  // Address width
77	  typedef logic [AxiAddrWidth-1:0] addr_t;
78	
79	  // ID width
80	  typedef logic [AxiIdWidth-1:0] id_t;
81	
82	  // Length of burst after upsizing
83	  typedef logic [$clog2(AxiSlvPortStrbWidth/AxiMstPortStrbWidth) + 7:0] burst_len_t;
84	
85	  // Internal AXI bus
86	  axi_mst_req_t  mst_req;
87	  axi_mst_resp_t mst_resp;
88	
89	  /**************
90	   *  ARBITERS  *
91	   **************/
92	
93	  // R
94	
95	  slv_r_chan_t [AxiMaxReads-1:0] slv_r_tran;
96	  logic        [AxiMaxReads-1:0] slv_r_valid_tran;
97	  logic        [AxiMaxReads-1:0] slv_r_ready_tran;
98	
99	  rr_arb_tree #(
100	    .NumIn    (AxiMaxReads ),
101	    .DataType (slv_r_chan_t),
102	    .AxiVldRdy(1'b1        ),
103	    .ExtPrio  (1'b0        ),
104	    .LockIn   (1'b1        )
105	  ) i_slv_r_arb (
106	    .clk_i  (clk_i             ),
107	    .rst_ni (rst_ni            ),
108	    .flush_i(1'b0              ),
109	    .rr_i   ('0                ),
110	    .req_i  (slv_r_valid_tran  ),
111	    .gnt_o  (slv_r_ready_tran  ),
112	    .data_i (slv_r_tran        ),
113	    .gnt_i  (slv_req_i.r_ready ),
114	    .req_o  (slv_resp_o.r_valid),
115	    .data_o (slv_resp_o.r      ),
116	    .idx_o  (/* Unused */      )
117	  );
118	
119	  logic [AxiMaxReads-1:0] mst_r_ready_tran;
120	  assign mst_req.r_ready = |mst_r_ready_tran;
121	
122	  // AR
123	
124	  id_t                    arb_slv_ar_id;
125	  logic                   arb_slv_ar_req;
126	  logic                   arb_slv_ar_gnt;
127	  logic [AxiMaxReads-1:0] arb_slv_ar_gnt_tran;
128	  // Multiplex AR slave between AR and AW for the injection of atomic operations with an R response.
129	  logic                   inject_aw_into_ar;
130	  logic                   inject_aw_into_ar_req;
131	  logic                   inject_aw_into_ar_gnt;
132	
133	  assign arb_slv_ar_gnt = |arb_slv_ar_gnt_tran;
134	
135	  rr_arb_tree #(
136	    .NumIn     (2         ),
137	    .DataWidth (AxiIdWidth),
138	    .ExtPrio   (1'b0      ),
139	    .AxiVldRdy (1'b1      ),
140	    .LockIn    (1'b0      )
141	  ) i_slv_ar_arb (
142	    .clk_i   (clk_i                                       ),
143	    .rst_ni  (rst_ni                                      ),
144	    .flush_i (1'b0                                        ),
145	    .rr_i    ('0                                          ),
146	    .req_i   ({inject_aw_into_ar_req, slv_req_i.ar_valid} ),
147	    .gnt_o   ({inject_aw_into_ar_gnt, slv_resp_o.ar_ready}),
148	    .data_i  ({slv_req_i.aw.id, slv_req_i.ar.id}          ),
149	    .req_o   (arb_slv_ar_req                              ),
150	    .gnt_i   (arb_slv_ar_gnt                              ),
151	    .data_o  (arb_slv_ar_id                               ),
152	    .idx_o   (inject_aw_into_ar                           )
153	  );
154	
155	  ar_chan_t [AxiMaxReads-1:0] mst_ar_tran;
156	  id_t      [AxiMaxReads-1:0] mst_ar_id;
157	  logic     [AxiMaxReads-1:0] mst_ar_valid_tran;
158	  logic     [AxiMaxReads-1:0] mst_ar_ready_tran;
159	  tran_id_t                   mst_req_idx;
160	
161	  rr_arb_tree #(
162	    .NumIn    (AxiMaxReads),
163	    .DataType (ar_chan_t  ),
164	    .AxiVldRdy(1'b1       ),
165	    .ExtPrio  (1'b0       ),
166	    .LockIn   (1'b1       )
167	  ) i_mst_ar_arb (
168	    .clk_i  (clk_i            ),
169	    .rst_ni (rst_ni           ),
170	    .flush_i(1'b0             ),
171	    .rr_i   ('0               ),
172	    .req_i  (mst_ar_valid_tran),
173	    .gnt_o  (mst_ar_ready_tran),
174	    .data_i (mst_ar_tran      ),
175	    .gnt_i  (mst_resp.ar_ready),
176	    .req_o  (mst_req.ar_valid ),
177	    .data_o (mst_req.ar       ),
178	    .idx_o  (mst_req_idx      )
179	  );
180	
181	  /*****************
182	   *  ERROR SLAVE  *
183	   *****************/
184	
185	  axi_mst_req_t  axi_err_req;
186	  axi_mst_resp_t axi_err_resp;
187	
188	  axi_err_slv #(
189	    .AxiIdWidth(AxiIdWidth          ),
190	    .Resp      (axi_pkg::RESP_SLVERR),
191	    .axi_req_t (axi_mst_req_t       ),
192	    .axi_resp_t(axi_mst_resp_t      )
193	  ) i_axi_err_slv (
194	    .clk_i     (clk_i       ),
195	    .rst_ni    (rst_ni      ),
196	    .test_i    (1'b0        ),
197	    .slv_req_i (axi_err_req ),
198	    .slv_resp_o(axi_err_resp)
199	  );
200	
201	  /***********
202	   *  DEMUX  *
203	   ***********/
204	
205	  // Requests can be sent either to the error slave,
206	  // or to the DWC's master port.
207	
208	  logic [AxiMaxReads-1:0] mst_req_ar_err;
209	  logic                   mst_req_aw_err;
210	
211	  axi_demux #(
212	    .AxiIdWidth (AxiIdWidth    ),
213	    .AxiLookBits(AxiIdWidth    ),
214	    .aw_chan_t  (aw_chan_t     ),
215	    .w_chan_t   (mst_w_chan_t  ),
216	    .b_chan_t   (b_chan_t      ),
217	    .ar_chan_t  (ar_chan_t     ),
218	    .r_chan_t   (mst_r_chan_t  ),
219	    .axi_req_t  (axi_mst_req_t ),
220	    .axi_resp_t (axi_mst_resp_t),
221	    .NoMstPorts (2             ),
222	    .MaxTrans   (AxiMaxReads   ),
223	    .SpillAw    (1'b1          ) // Required to break dependency between AW and W channels
224	  ) i_axi_demux (
225	    .clk_i          (clk_i                      ),
226	    .rst_ni         (rst_ni                     ),
227	    .test_i         (1'b0                       ),
228	    .mst_reqs_o     ({axi_err_req, mst_req_o}   ),
229	    .mst_resps_i    ({axi_err_resp, mst_resp_i} ),
230	    .slv_ar_select_i(mst_req_ar_err[mst_req_idx]),
231	    .slv_aw_select_i(mst_req_aw_err             ),
232	    .slv_req_i      (mst_req                    ),
233	    .slv_resp_o     (mst_resp                   )
234	  );
235	
236	  /**********
237	   *  READ  *
238	   **********/
239	
240	  typedef enum logic [2:0] {
241	    R_IDLE         ,
242	    R_INJECT_AW    ,
243	    R_PASSTHROUGH  ,
244	    R_INCR_DOWNSIZE,
245	    R_SPLIT_INCR_DOWNSIZE
246	  } r_state_e;
247	
248	  typedef struct packed {
249	    ar_chan_t ar                ;
250	    logic ar_valid              ;
251	    logic ar_throw_error        ;
252	    slv_r_chan_t r              ;
253	    logic r_valid               ;
254	    burst_len_t burst_len       ;
255	    axi_pkg::size_t orig_ar_size;
256	    logic injected_aw           ;
257	  } r_req_t;
258	
259	  // Write-related type, but w_req_q is referenced from Read logic
260	  typedef struct packed {
261	    aw_chan_t aw                  ;
262	    logic aw_valid                ;
263	    logic aw_throw_error          ;
264	    burst_len_t burst_len         ;
265	    axi_pkg::len_t orig_aw_len    ;
266	    axi_pkg::burst_t orig_aw_burst;
267	    axi_pkg::resp_t burst_resp    ;
268	    axi_pkg::size_t orig_aw_size  ;
269	  } w_req_t;
270	
271	  w_req_t   w_req_d, w_req_q;
272	
273	  // Decide which downsizer will handle the incoming AXI transaction
274	  logic     [AxiMaxReads-1:0] idle_read_downsizer;
275	  tran_id_t                   idx_ar_downsizer;
276	
277	  // Find an idle downsizer to handle this transaction
278	  tran_id_t idx_idle_downsizer;
279	  lzc #(
280	    .WIDTH(AxiMaxReads)
281	  ) i_idle_lzc (
282	    .in_i   (idle_read_downsizer),
283	    .cnt_o  (idx_idle_downsizer ),
284	    .empty_o(/* Unused */       )
285	  );
286	
287	  // Is there already another downsizer handling a transaction with the same id
288	  logic     [AxiMaxReads-1:0] id_clash_downsizer;
289	  tran_id_t                   idx_id_clash_downsizer;
290	  for (genvar t = 0; t < AxiMaxReads; t++) begin: gen_id_clash
291	    assign id_clash_downsizer[t] = arb_slv_ar_id == mst_ar_id[t] && !idle_read_downsizer[t];
292	  end
293	
294	  onehot_to_bin #(
295	    .ONEHOT_WIDTH(AxiMaxReads)
296	  ) i_id_clash_onehot_to_bin (
297	    .onehot(id_clash_downsizer    ),
298	    .bin   (idx_id_clash_downsizer)
299	  );
300	
301	  // Choose an idle downsizer, unless there is an id clash
302	  assign idx_ar_downsizer = (|id_clash_downsizer) ? idx_id_clash_downsizer : idx_idle_downsizer;
303	
304	  // This ID queue is used to resolve which downsizer is handling
305	  // each outstanding read transaction.
306	
307	  logic     [AxiMaxReads-1:0] idqueue_push;
308	  logic     [AxiMaxReads-1:0] idqueue_pop;
309	  tran_id_t                   idqueue_id;
310	  logic                       idqueue_valid;
311	
312	  id_queue #(
313	    .ID_WIDTH(AxiIdWidth ),
314	    .CAPACITY(AxiMaxReads),
315	    .data_t  (tran_id_t  )
316	  ) i_read_id_queue (
317	    .clk_i           (clk_i           ),
318	    .rst_ni          (rst_ni          ),
319	    .inp_id_i        (arb_slv_ar_id   ),
320	    .inp_data_i      (idx_ar_downsizer),
321	    .inp_req_i       (|idqueue_push   ),
322	    .inp_gnt_o       (/* Unused  */   ),
323	    .oup_id_i        (mst_resp.r.id   ),
324	    .oup_pop_i       (|idqueue_pop    ),
325	    .oup_req_i       (1'b1            ),
326	    .oup_data_o      (idqueue_id      ),
327	    .oup_data_valid_o(idqueue_valid   ),
328	    .oup_gnt_o       (/* Unused  */   ),
329	    .exists_data_i   ('0              ),
330	    .exists_mask_i   ('0              ),
331	    .exists_req_i    ('0              ),
332	    .exists_o        (/* Unused  */   ),
333	    .exists_gnt_o    (/* Unused  */   ),
334	    .full_o          (/* Unused  */   ),
335	    .empty_o         (/* Unused  */   )
336	  );
337	
338	  for (genvar t = 0; unsigned'(t) < AxiMaxReads; t++) begin: gen_read_downsizer
339	    r_state_e r_state_d, r_state_q;
340	    r_req_t r_req_d    , r_req_q  ;
341	
342	    // Are we idle?
343	    assign idle_read_downsizer[t] = (r_state_q == R_IDLE) || (r_state_q == R_INJECT_AW);
344	
345	    // Byte-grouped data signal for the serialization step
346	    slv_data_t r_data;
347	
348	    always_comb begin
349	      // Maintain state
350	      r_state_d = r_state_q;
351	      r_req_d   = r_req_q  ;
352	
353	      // AR Channel
354	      mst_ar_tran[t]       = r_req_q.ar      ;
355	      mst_ar_id[t]         = r_req_q.ar.id   ;
356	      mst_ar_valid_tran[t] = r_req_q.ar_valid;
357	
358	      // Throw an error
359	      mst_req_ar_err[t] = r_req_q.ar_throw_error;
360	
361	      // R Channel
362	      slv_r_tran[t]       = r_req_q.r      ;
363	      slv_r_valid_tran[t] = r_req_q.r_valid;
