368	      arb_slv_ar_gnt_tran[t] = 1'b0;
369	
370	      mst_r_ready_tran[t] = 1'b0;
371	
372	      // Got a grant on the AR channel
373	      if (mst_ar_valid_tran[t] && mst_ar_ready_tran[t]) begin
374	        r_req_d.ar_valid       = 1'b0;
375	        r_req_d.ar_throw_error = 1'b0;
376	      end
377	
378	      // Initialize r_data
379	      r_data = r_req_q.r.data;
380	
381	      case (r_state_q)
382	        R_IDLE : begin
383	          // Reset channels
384	          r_req_d.ar = '0;
385	          r_req_d.r  = '0;
386	
387	          // New read request
388	          if (arb_slv_ar_req && (idx_ar_downsizer == t)) begin
389	            arb_slv_ar_gnt_tran[t] = 1'b1;
390	
391	            // Push to ID queue
392	            idqueue_push[t] = 1'b1;
393	
394	            // Must inject an AW request into this upsizer
