396	              r_state_d = R_INJECT_AW;
397	            end else begin
398	              // Default state
399	              r_state_d = R_PASSTHROUGH;
400	
401	              // Save beat
402	              r_req_d.ar           = slv_req_i.ar        ;
403	              r_req_d.ar_valid     = 1'b1                ;
404	              r_req_d.burst_len    = slv_req_i.ar.len    ;
405	              r_req_d.orig_ar_size = slv_req_i.ar.size   ;
406	              r_req_d.injected_aw  = 1'b0                ;
407	              r_req_d.r.resp       = axi_pkg::RESP_EXOKAY;
408	
409	              case (r_req_d.ar.burst)
410	                axi_pkg::BURST_INCR : begin
411	                  automatic addr_t size_mask;
412	                  automatic addr_t conv_ratio;
413	                  automatic addr_t align_adj;
414	                  // Evaluate downsize ratio
415	                  size_mask  = (1 << r_req_d.ar.size) - 1                                              ;
416	                  conv_ratio = ((1 << r_req_d.ar.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
417	
418	                  // Evaluate output burst length
419	                  align_adj         = (r_req_d.ar.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
420	                  r_req_d.burst_len = (r_req_d.ar.len + 1) * conv_ratio - align_adj - 1                     ;
421	
422	                  if (conv_ratio != 1) begin
423	                    r_req_d.ar.size = AxiMstPortMaxSize;
424	
425	                    if (r_req_d.burst_len <= 255) begin
426	                      r_state_d      = R_INCR_DOWNSIZE  ;
427	                      r_req_d.ar.len = r_req_d.burst_len;
428	                    end else begin
429	                      r_state_d      = R_SPLIT_INCR_DOWNSIZE;
430	                      r_req_d.ar.len = 255 - align_adj      ;
431	                    end
432	                  end
433	                end
434	
435	                axi_pkg::BURST_FIXED: begin
436	                  // Single transaction
437	                  if (r_req_d.ar.len == '0) begin
438	                    automatic addr_t size_mask;
439	                    automatic addr_t conv_ratio;
440	                    automatic addr_t align_adj;
441	                    // Evaluate downsize ratio
442	                    size_mask  = (1 << r_req_d.ar.size) - 1                                              ;
443	                    conv_ratio = ((1 << r_req_d.ar.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
444	
445	                    // Evaluate output burst length
446	                    align_adj         = (r_req_d.ar.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
447	                    r_req_d.burst_len = (conv_ratio >= align_adj + 1) ? (conv_ratio - align_adj - 1) : 0      ;
448	
449	                    if (conv_ratio != 1) begin
450	                      r_state_d        = R_INCR_DOWNSIZE    ;
451	                      r_req_d.ar.len   = r_req_d.burst_len  ;
452	                      r_req_d.ar.size  = AxiMstPortMaxSize  ;
453	                      r_req_d.ar.burst = axi_pkg::BURST_INCR;
454	                    end
455	                  end else begin
456	                    // The downsizer does not support fixed burts
457	                    r_req_d.ar_throw_error = 1'b1;
458	                  end
459	                end
460	
461	                axi_pkg::BURST_WRAP: begin
462	                  // The DW converter does not support this type of burst.
463	                  r_state_d              = R_PASSTHROUGH;
464	                  r_req_d.ar_throw_error = 1'b1         ;
465	                end
466	
467	                default: ;
468	              endcase
469	            end
470	          end
471	        end
472	
473	        R_INJECT_AW : begin
474	          // Save beat
475	          r_req_d.ar.id        = w_req_q.aw.id        ;
476	          r_req_d.ar.addr      = w_req_q.aw.addr      ;
477	          r_req_d.ar.size      = w_req_q.orig_aw_size ;
478	          r_req_d.ar.burst     = w_req_q.orig_aw_burst;
479	          r_req_d.ar.len       = w_req_q.orig_aw_len  ;
480	          r_req_d.ar.lock      = w_req_q.aw.lock      ;
481	          r_req_d.ar.cache     = w_req_q.aw.cache     ;
482	          r_req_d.ar.prot      = w_req_q.aw.prot      ;
483	          r_req_d.ar.qos       = w_req_q.aw.qos       ;
484	          r_req_d.ar.region    = w_req_q.aw.region    ;
485	          r_req_d.ar.user      = w_req_q.aw.user      ;
486	          r_req_d.ar_valid     = 1'b0                 ; // Injected "AR"s from AW are not valid.
487	          r_req_d.burst_len    = w_req_q.orig_aw_len  ;
488	          r_req_d.orig_ar_size = w_req_q.orig_aw_size ;
489	          r_req_d.injected_aw  = 1'b1                 ;
490	          r_req_d.r.resp       = axi_pkg::RESP_EXOKAY ;
491	
492	          // Default state
493	          r_state_d = R_PASSTHROUGH;
494	
495	          case (r_req_d.ar.burst)
496	            axi_pkg::BURST_INCR : begin
497	              automatic addr_t size_mask;
498	              automatic addr_t conv_ratio;
499	              automatic addr_t align_adj;
500	              // Evaluate downsize ratio
501	              size_mask  = (1 << r_req_d.ar.size) - 1                                              ;
502	              conv_ratio = ((1 << r_req_d.ar.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
503	
504	              // Evaluate output burst length
505	              align_adj         = (r_req_d.ar.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
506	              r_req_d.burst_len = (r_req_d.ar.len + 1) * conv_ratio - align_adj - 1                     ;
507	
508	              if (conv_ratio != 1) begin
509	                r_req_d.ar.size = AxiMstPortMaxSize;
510	
511	                if (r_req_d.burst_len <= 255) begin
512	                  r_state_d      = R_INCR_DOWNSIZE  ;
513	                  r_req_d.ar.len = r_req_d.burst_len;
514	                end else begin
515	                  r_state_d      = R_SPLIT_INCR_DOWNSIZE;
516	                  r_req_d.ar.len = 255 - align_adj      ;
517	                end
518	              end
519	            end
520	
521	            axi_pkg::BURST_FIXED: begin
522	              // Single transaction
523	              if (r_req_d.ar.len == '0) begin
524	                automatic addr_t size_mask;
525	                automatic addr_t conv_ratio;
526	                automatic addr_t align_adj;
527	                // Evaluate downsize ratio
528	                size_mask  = (1 << r_req_d.ar.size) - 1                                              ;
529	                conv_ratio = ((1 << r_req_d.ar.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
530	
531	                // Evaluate output burst length
532	                align_adj         = (r_req_d.ar.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
533	                r_req_d.burst_len = (conv_ratio >= align_adj + 1) ? (conv_ratio - align_adj - 1) : 0;
534	
535	                if (conv_ratio != 1) begin
536	                  r_state_d        = R_INCR_DOWNSIZE    ;
537	                  r_req_d.ar.len   = r_req_d.burst_len  ;
538	                  r_req_d.ar.size  = AxiMstPortMaxSize  ;
539	                  r_req_d.ar.burst = axi_pkg::BURST_INCR;
540	                end
541	              end else begin
542	                // The downsizer does not support fixed burts
543	                r_req_d.ar_throw_error = 1'b1;
544	              end
545	            end
546	
547	            axi_pkg::BURST_WRAP: begin
548	              // The DW converter does not support this type of burst.
549	              r_state_d              = R_PASSTHROUGH;
550	              r_req_d.ar_throw_error = 1'b1         ;
551	            end
552	
553	            default: ;
554	          endcase
555	        end
556	
557	        R_PASSTHROUGH, R_INCR_DOWNSIZE, R_SPLIT_INCR_DOWNSIZE: begin
558	          // Got a grant on the R channel
559	          if (slv_r_valid_tran[t] && slv_r_ready_tran[t]) begin
560	            r_req_d.r       = '0  ;
561	            r_req_d.r_valid = 1'b0;
562	            r_data          = '0  ;
563	          end
564	
565	          // Request was accepted
566	          if (!r_req_q.ar_valid) begin
567	            // Our turn
568	            if ((idqueue_id == t) && idqueue_valid) begin
569	              // Ready to accept more data
570	              if (!slv_r_valid_tran[t] || (slv_r_valid_tran[t] && slv_r_ready_tran[t])) begin
571	                mst_r_ready_tran[t] = 1'b1;
572	
573	                if (mst_resp.r_valid) begin
574	                  automatic addr_t mst_port_offset;
575	                  automatic addr_t slv_port_offset;
576	                  mst_port_offset = AxiMstPortStrbWidth == 1 ? '0 : r_req_q.ar.addr[idx_width(AxiMstPortStrbWidth)-1:0];
577	                  slv_port_offset = AxiSlvPortStrbWidth == 1 ? '0 : r_req_q.ar.addr[idx_width(AxiSlvPortStrbWidth)-1:0];
578	
579	                  // Serialization
580	                  for (int b = 0; b < AxiSlvPortStrbWidth; b++) begin
581	                    if ((b >= slv_port_offset) &&
582	                        (b - slv_port_offset < (1 << r_req_q.orig_ar_size)) &&
583	                        (b + mst_port_offset - slv_port_offset < AxiMstPortStrbWidth)) begin
584	                      r_data[b] = mst_resp.r.data[8*(b + mst_port_offset - slv_port_offset) +: 8];
585	                    end
586	                  end
587	
588	                  r_req_d.burst_len = r_req_q.burst_len - 1   ;
589	                  r_req_d.ar.len    = r_req_q.ar.len - 1      ;
590	                  r_req_d.r.data    = r_data                  ;
591	                  r_req_d.r.last    = (r_req_q.burst_len == 0);
592	                  r_req_d.r.id      = mst_resp.r.id           ;
593	                  r_req_d.r.user    = mst_resp.r.user         ;
594	
595	                  // Merge response of this beat with prior one according to precedence rules.
596	                  r_req_d.r.resp = axi_pkg::resp_precedence(r_req_q.r.resp, mst_resp.r.resp);
597	
598	                  case (r_req_d.ar.burst)
599	                    axi_pkg::BURST_INCR: begin
600	                      r_req_d.ar.addr = aligned_addr(axi_pkg::largest_addr_t'(r_req_q.ar.addr), r_req_q.ar.size) + (1 << r_req_q.ar.size);
601	                    end
602	                    axi_pkg::BURST_FIXED: begin
603	                      r_req_d.ar.addr = r_req_q.ar.addr;
604	                    end
605	                  endcase
606	
607	                  if (r_req_q.burst_len == 0) begin
608	                    idqueue_pop[t] = 1'b1;
609	                  end
610	
611	                  case (r_state_q)
612	                    R_PASSTHROUGH : begin
613	                      // Forward data as soon as we can
614	                      r_req_d.r_valid = 1'b1;
615	                    end
616	
617	                    R_INCR_DOWNSIZE, R_SPLIT_INCR_DOWNSIZE: begin
618	                      // Forward when the burst is finished, or after filling up a word
619	                      if (r_req_q.burst_len == 0 ||
620	                          (aligned_addr(axi_pkg::largest_addr_t'(r_req_d.ar.addr), r_req_q.orig_ar_size) !=
621	                           aligned_addr(axi_pkg::largest_addr_t'(r_req_q.ar.addr), r_req_q.orig_ar_size)   )) begin
622	                        r_req_d.r_valid = 1'b1;
623	                      end
624	                    end
625	                  endcase
626	
627	                  // Trigger another burst request, if needed
628	                  if (r_state_q == R_SPLIT_INCR_DOWNSIZE) begin
629	                    // Finished current burst, but whole transaction hasn't finished
630	                    if (r_req_q.ar.len == '0 && r_req_q.burst_len != '0) begin
631	                      r_req_d.ar_valid = !r_req_q.injected_aw;
632	                      r_req_d.ar.len   = (r_req_d.burst_len <= 255) ? r_req_d.burst_len : 255;
633	                    end
634	                  end
635	                end
636	              end
637	            end
638	          end
639	
640	          if (slv_r_valid_tran[t] && slv_r_ready_tran[t]) begin
641	            if (r_req_q.burst_len == '1) begin
642	              r_state_d = R_IDLE;
643	            end
644	          end
645	        end
646	
647	        default: ;
648	      endcase
649	    end
650	
651	    always_ff @(posedge clk_i or negedge rst_ni) begin
652	      if (!rst_ni) begin
653	        r_state_q <= R_IDLE;
654	        r_req_q   <= '0    ;
655	      end else begin
656	        r_state_q <= r_state_d;
657	        r_req_q   <= r_req_d  ;
658	      end
659	    end
660	  end : gen_read_downsizer
