663	   *  WRITE  *
664	   ***********/
665	  typedef enum logic [1:0] {
666	    W_IDLE         ,
667	    W_PASSTHROUGH  ,
668	    W_INCR_DOWNSIZE,
669	    W_SPLIT_INCR_DOWNSIZE
670	  } w_state_e;
671	
672	  w_state_e w_state_d, w_state_q;
673	
674	  // This FIFO holds the number of bursts generated by each write transactions handled by this downsizer.
675	  // This is used to forward only the correct B beats to the slave.
676	  logic forward_b_beat_i;
677	  logic forward_b_beat_o;
678	  logic forward_b_beat_push;
679	  logic forward_b_beat_pop;
680	  logic forward_b_beat_full;
681	
682	  fifo_v3 #(
683	    .DATA_WIDTH  (1          ),
684	    .DEPTH       (AxiMaxReads),
685	    .FALL_THROUGH(1'b1       )
686	  ) i_forward_b_beats_queue (
687	    .clk_i     (clk_i               ),
688	    .rst_ni    (rst_ni              ),
689	    .flush_i   (1'b0                ),
690	    .testmode_i(1'b0                ),
691	    .data_i    (forward_b_beat_i    ),
692	    .push_i    (forward_b_beat_push ),
693	    .full_o    (forward_b_beat_full ),
694	    .data_o    (forward_b_beat_o    ),
695	    .pop_i     (forward_b_beat_pop  ),
696	    .empty_o   (/* Unused */        ),
697	    .usage_o   (/* Unused */        )
698	  );
699	
700	  // Byte-grouped data signal for the lane steering step
701	  mst_data_t w_data;
702	
703	  always_comb begin
704	    inject_aw_into_ar_req = 1'b0;
705	
706	    // i_num_b_beats default state
707	    forward_b_beat_i    = '0  ;
708	    forward_b_beat_push = 1'b0;
709	    forward_b_beat_pop  = 1'b0;
710	
711	    // Maintain state
712	    w_state_d = w_state_q;
713	    w_req_d   = w_req_q  ;
714	
715	    // AW Channel
716	    mst_req.aw          = w_req_q.aw      ;
717	    mst_req.aw_valid    = w_req_q.aw_valid;
718	    slv_resp_o.aw_ready = '0              ;
719	
720	    // Throw an error.
721	    mst_req_aw_err = w_req_q.aw_throw_error;
722	
723	    // W Channel
724	    mst_req.w          = '0;
725	    mst_req.w_valid    = '0;
726	    slv_resp_o.w_ready = '0;
727	
728	    // Initialize w_data
729	    w_data = '0;
730	
731	    // B Channel (No latency)
732	    if (mst_resp.b_valid) begin
733	      // Merge response of this burst with prior one according to precedence rules.
734	      w_req_d.burst_resp = axi_pkg::resp_precedence(w_req_q.burst_resp, mst_resp.b.resp);
735	    end
736	    slv_resp_o.b      = mst_resp.b        ;
737	    slv_resp_o.b.resp = w_req_d.burst_resp;
