743	      mst_req.b_ready    = slv_req_i.b_ready;
744	
745	      // Got an ack on the B channel. Pop transaction.
746	      if (mst_req.b_ready && mst_resp.b_valid) begin
747	        forward_b_beat_pop = 1'b1;
748	      end
749	    end else begin
750	      // Otherwise, just acknowlegde the B beats
751	      slv_resp_o.b_valid = 1'b0            ;
752	      mst_req.b_ready    = 1'b1            ;
753	      forward_b_beat_pop = mst_resp.b_valid;
754	    end
755	
756	    // Got a grant on the AW channel
757	    if (mst_req.aw_valid & mst_resp.aw_ready) begin
758	      w_req_d.aw_valid       = 1'b0;
759	      w_req_d.aw_throw_error = 1'b0;
760	    end
761	
762	    case (w_state_q)
763	      W_PASSTHROUGH, W_INCR_DOWNSIZE, W_SPLIT_INCR_DOWNSIZE: begin
764	        // Request was accepted
765	        if (!w_req_q.aw_valid) begin
766	          if (slv_req_i.w_valid) begin
767	            automatic logic [idx_width(AxiMstPortStrbWidth)-1:0] mst_port_offset;
768	            automatic logic [idx_width(AxiSlvPortStrbWidth)-1:0] slv_port_offset;
769	            mst_port_offset = AxiMstPortStrbWidth == 1 ? '0 : w_req_q.aw.addr[idx_width(AxiMstPortStrbWidth)-1:0];
770	            slv_port_offset = AxiSlvPortStrbWidth == 1 ? '0 : w_req_q.aw.addr[idx_width(AxiSlvPortStrbWidth)-1:0];
771	
772	            // Valid output
773	            mst_req.w_valid = !(forward_b_beat_full && w_req_q.aw.len == 0);
774	            mst_req.w.last  = w_req_q.aw.len == 0;
775	            mst_req.w.user  = slv_req_i.w.user   ;
776	
777	            // Lane steering
778	            for (int b = 0; b < AxiSlvPortStrbWidth; b++) begin
779	              if ((b >= slv_port_offset) &&
780	                  (b - slv_port_offset < (1 << w_req_q.orig_aw_size)) &&
781	                  (b + mst_port_offset - slv_port_offset < AxiMstPortStrbWidth)) begin
782	                w_data[b + mst_port_offset - slv_port_offset]         = slv_req_i.w.data[8*b +: 8];
783	                mst_req.w.strb[b + mst_port_offset - slv_port_offset] = slv_req_i.w.strb[b]       ;
784	              end
785	            end
786	            mst_req.w.data = w_data;
787	          end
788	        end
789	
790	        // Acknowledgment
791	        if (mst_resp.w_ready && mst_req.w_valid) begin
792	          w_req_d.burst_len = w_req_q.burst_len - 1;
793	          w_req_d.aw.len    = w_req_q.aw.len - 1   ;
794	
795	          case (w_req_d.aw.burst)
796	            axi_pkg::BURST_INCR: begin
797	              w_req_d.aw.addr = aligned_addr(axi_pkg::largest_addr_t'(w_req_q.aw.addr), w_req_q.aw.size) + (1 << w_req_q.aw.size);
798	            end
799	            axi_pkg::BURST_FIXED: begin
800	              w_req_d.aw.addr = w_req_q.aw.addr;
801	            end
802	          endcase
803	
804	          case (w_state_q)
805	            W_PASSTHROUGH: begin
806	              slv_resp_o.w_ready = 1'b1;
807	            end
808	
809	            W_INCR_DOWNSIZE, W_SPLIT_INCR_DOWNSIZE: begin
810	              if (w_req_q.burst_len == 0 ||
811	                  (aligned_addr(axi_pkg::largest_addr_t'(w_req_d.aw.addr), w_req_q.orig_aw_size) !=
812	                   aligned_addr(axi_pkg::largest_addr_t'(w_req_q.aw.addr), w_req_q.orig_aw_size)   )) begin
813	                slv_resp_o.w_ready = 1'b1;
814	              end
815	            end
816	          endcase
817	
818	          // Trigger another burst request, if needed
819	          if (w_state_q == W_SPLIT_INCR_DOWNSIZE) begin
820	            // Finished current burst, but whole transaction hasn't finished
821	            if (w_req_q.aw.len == '0 && w_req_q.burst_len != '0) begin
822	              w_req_d.aw_valid = 1'b1;
823	              w_req_d.aw.len   = (w_req_d.burst_len <= 255) ? w_req_d.burst_len : 255;
824	
825	              // We will receive an extraneous B beat. Ignore it.
826	              forward_b_beat_i    = 1'b0;
827	              forward_b_beat_push = 1'b1;
828	            end
829	          end
830	
831	          if (w_req_q.burst_len == 0) begin
832	            w_state_d = W_IDLE;
833	
834	            forward_b_beat_push = 1'b1;
835	            forward_b_beat_i    = 1'b1;
836	          end
837	        end
838	      end
839	    default: ;
840	    endcase
841	
842	    // Can start a new request as soon as w_state_d is W_IDLE
843	    if (w_state_d == W_IDLE) begin
844	      // Reset channels
845	      w_req_d.aw             = '0                  ;
846	      w_req_d.aw_valid       = 1'b0                ;
847	      w_req_d.aw_throw_error = 1'b0                ;
848	      w_req_d.burst_resp     = axi_pkg::RESP_EXOKAY;
849	
850	      if (!forward_b_beat_full) begin
851	        if (slv_req_i.aw_valid && slv_req_i.aw.atop[axi_pkg::ATOP_R_RESP]) begin // ATOP with an R response
852	          inject_aw_into_ar_req = 1'b1                 ;
853	          slv_resp_o.aw_ready   = inject_aw_into_ar_gnt;
854	        end else begin // Regular AW
855	          slv_resp_o.aw_ready = 1'b1;
856	        end
857	
858	        // New write request
859	        if (slv_req_i.aw_valid && slv_resp_o.aw_ready) begin
860	          // Default state
861	          w_state_d = W_PASSTHROUGH;
862	
863	          // Save beat
864	          w_req_d.aw            = slv_req_i.aw      ;
865	          w_req_d.aw_valid      = 1'b1              ;
866	          w_req_d.burst_len     = slv_req_i.aw.len  ;
867	          w_req_d.orig_aw_len   = slv_req_i.aw.len  ;
868	          w_req_d.orig_aw_size  = slv_req_i.aw.size ;
869	          w_req_d.orig_aw_burst = slv_req_i.aw.burst;
870	
871	          case (slv_req_i.aw.burst)
872	            axi_pkg::BURST_INCR: begin
873	              automatic addr_t size_mask;
874	              automatic addr_t conv_ratio;
875	              automatic addr_t align_adj;
876	              // Evaluate downsize ratio
877	              size_mask  = (1 << slv_req_i.aw.size) - 1                                              ;
878	              conv_ratio = ((1 << slv_req_i.aw.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
879	
880	              // Evaluate output burst length
881	              align_adj         = (slv_req_i.aw.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
882	              w_req_d.burst_len = (slv_req_i.aw.len + 1) * conv_ratio - align_adj - 1                     ;
883	
884	              if (conv_ratio != 1) begin
885	                w_req_d.aw.size = AxiMstPortMaxSize;
886	
887	                if (w_req_d.burst_len <= 255) begin
888	                  w_state_d      = W_INCR_DOWNSIZE  ;
889	                  w_req_d.aw.len = w_req_d.burst_len;
890	                end else begin
891	                  w_state_d      = W_SPLIT_INCR_DOWNSIZE;
892	                  w_req_d.aw.len = 255 - align_adj      ;
893	                end
894	              end
895	            end
896	
897	            axi_pkg::BURST_FIXED: begin
898	              // Single transaction
899	              if (slv_req_i.aw.len == '0) begin
900	                automatic addr_t size_mask;
901	                automatic addr_t conv_ratio;
902	                automatic addr_t align_adj;
903	                // Evaluate downsize ratio
904	                size_mask  = (1 << slv_req_i.aw.size) - 1                                              ;
905	                conv_ratio = ((1 << slv_req_i.aw.size) + AxiMstPortStrbWidth - 1) / AxiMstPortStrbWidth;
906	
907	                // Evaluate output burst length
908	                align_adj         = (slv_req_i.aw.addr & size_mask & ~MstPortByteMask) / AxiMstPortStrbWidth;
909	                w_req_d.burst_len = (conv_ratio >= align_adj + 1) ? (conv_ratio - align_adj - 1) : 0        ;
910	
911	                if (conv_ratio != 1) begin
912	                  w_state_d        = W_INCR_DOWNSIZE    ;
913	                  w_req_d.aw.len   = w_req_d.burst_len  ;
914	                  w_req_d.aw.size  = AxiMstPortMaxSize  ;
915	                  w_req_d.aw.burst = axi_pkg::BURST_INCR;
916	                end
917	              end else begin
918	                // The downsizer does not support fixed bursts
919	                w_req_d.aw_throw_error = 1'b1;
920	              end
921	            end
922	
923	            axi_pkg::BURST_WRAP: begin
924	              // The DW converter does not support this type of burst.
925	              w_state_d              = W_PASSTHROUGH;
926	              w_req_d.aw_throw_error = 1'b1         ;
927	            end
928	
929	            default: ;
930	          endcase
931	        end
932	      end
933	    end
934	  end
935	
936	  always_ff @(posedge clk_i or negedge rst_ni) begin
937	    if (!rst_ni) begin
938	      w_state_q <= W_IDLE;
939	      w_req_q   <= '0    ;
940	    end else begin
941	      w_state_q <= w_state_d;
942	      w_req_q   <= w_req_d  ;
943	    end
944	  end
945	
946	endmodule : axi_dw_downsizer
947

