13	
14	// `axi_dw_upsizer_monitor` implements an AXI bus monitor that is tuned
15	// for the AXI Data Width Converters. It snoops on the slave and master port
16	// of the DWCs and populates FIFOs and ID queues to validate that no
17	// AXI beats get lost.
18	
19	package tb_axi_dw_pkg       ;
20	  import axi_pkg::len_t     ;
21	  import axi_pkg::burst_t   ;
22	  import axi_pkg::size_t    ;
23	  import axi_pkg::cache_t   ;
24	  import axi_pkg::modifiable;
25	
26	  /****************
27	   *  BASE CLASS  *
28	   ****************/
29	
30	  class axi_dw_monitor #(
31	      parameter int unsigned AxiAddrWidth       ,
32	      parameter int unsigned AxiSlvPortDataWidth,
33	      parameter int unsigned AxiMstPortDataWidth,
34	      parameter int unsigned AxiIdWidth         ,
35	      parameter int unsigned AxiUserWidth       ,
36	      // Stimuli application and test time
37	      parameter time TimeTest
38	    );
39	
40	    localparam AxiSlvPortStrbWidth = AxiSlvPortDataWidth / 8;
41	    localparam AxiMstPortStrbWidth = AxiMstPortDataWidth / 8;
42	
43	    localparam AxiSlvPortMaxSize = $clog2(AxiSlvPortStrbWidth);
44	    localparam AxiMstPortMaxSize = $clog2(AxiMstPortStrbWidth);
45	
46	    typedef logic [AxiIdWidth-1:0] axi_id_t    ;
47	    typedef logic [AxiAddrWidth-1:0] axi_addr_t;
