645	        end
646	        // Modifiable transaction
647	        else begin
648	          case (slv_port_axi.aw_burst)
649	            // Passthrough upsize
650	            axi_pkg::BURST_FIXED: begin
651	              exp_aw = '{
652	                axi_id   : slv_port_axi.aw_id   ,
653	                axi_addr : slv_port_axi.aw_addr ,
654	                axi_len  : slv_port_axi.aw_len  ,
