696	    task automatic mon_slv_port_w ();
697	      if (act_slv_port_w_queue.size() != 0) begin
698	        exp_slv_rw_t act_slv_w = act_slv_port_w_queue[0];
699	
700	        if (act_mst_port_aw_queue.size() != 0 && act_slv_port_aw_queue.size() != 0) begin
701	          // Retrieve the AW requests related to this W beat
702	          exp_ax_t act_mst_aw = act_mst_port_aw_queue[0];
703	          exp_ax_t act_slv_aw = act_slv_port_aw_queue[0];
704	
705	          // Calculate the offsets
706	          shortint unsigned mst_port_lower_byte =
707	          axi_pkg::beat_lower_byte(act_mst_aw.axi_addr, act_mst_aw.axi_size, act_mst_aw.axi_len, act_mst_aw.axi_burst, AxiMstPortStrbWidth, mst_port_w_cnt);
708	          shortint unsigned mst_port_upper_byte =
709	          axi_pkg::beat_upper_byte(act_mst_aw.axi_addr, act_mst_aw.axi_size, act_mst_aw.axi_len, act_mst_aw.axi_burst, AxiMstPortStrbWidth, mst_port_w_cnt);
710	          shortint unsigned slv_port_lower_byte =
711	          axi_pkg::beat_lower_byte(act_slv_aw.axi_addr, act_slv_aw.axi_size, act_slv_aw.axi_len, act_slv_aw.axi_burst, AxiSlvPortStrbWidth, slv_port_w_cnt);
712	          shortint unsigned slv_port_upper_byte =
713	          axi_pkg::beat_upper_byte(act_slv_aw.axi_addr, act_slv_aw.axi_size, act_slv_aw.axi_len, act_slv_aw.axi_burst, AxiSlvPortStrbWidth, slv_port_w_cnt);
714	
715	          shortint unsigned bytes_copied = 0;
716	          // Pointer inside the outcoming word
717	          if (mst_port_w_pnt == '1)
718	            mst_port_w_pnt = mst_port_lower_byte;
719	
720	          mst_port_w.axi_last = mst_port_w_cnt == act_mst_aw.axi_len;
721	          for (shortint unsigned b = slv_port_lower_byte; b <= slv_port_upper_byte; b++) begin
722	            if (b + mst_port_w_pnt - slv_port_lower_byte == AxiMstPortStrbWidth)
723	              break;
724	            mst_port_w.axi_data[8*(b + mst_port_w_pnt - slv_port_lower_byte) +: 8] = act_slv_w.axi_data[8*b +: 8];
725	            mst_port_w.axi_strb[b + mst_port_w_pnt - slv_port_lower_byte]          = act_slv_w.axi_strb[b]       ;
726	            bytes_copied++;
727	          end
728	
729	          // Increment the len counters
730	          slv_port_w_cnt++              ;
731	          mst_port_w_pnt += bytes_copied;
732	
733	          if (act_mst_aw.axi_burst == axi_pkg::BURST_FIXED // No upsizing
734	              || mst_port_w_pnt == AxiMstPortStrbWidth     // Filled up an outcoming W beat
735	              || act_slv_w.axi_last                        // Last beat of a W burst
736	            ) begin
737	            // Don't care for the bits outside these accessed by this request
738	            for (int unsigned b = 0; b < AxiMstPortStrbWidth; b++)
739	              if (!(mst_port_lower_byte <= b && b <= mst_port_upper_byte))
740	                mst_port_w.axi_data[8*b +: 8] = {8{1'b?}};
741	
742	            this.exp_mst_port_w_queue.push_back(mst_port_w);
743	            incr_expected_tests(3)                         ;
744	
745	            // Increment the len counter
746	            mst_port_w_cnt++;
747	
748	            // Reset W beat
749	            mst_port_w     = '0;
750	            mst_port_w_pnt = '1;
751	          end
752	
753	          // Pop the AW request from the queues
754	          if (slv_port_w_cnt == act_slv_aw.axi_len + 1) begin
755	            void'(act_slv_port_aw_queue.pop_front());
756	            slv_port_w_cnt = 0;
757	          end
758	          if (mst_port_w_cnt == act_mst_aw.axi_len + 1) begin
759	            void'(act_mst_port_aw_queue.pop_front());
760	            mst_port_w_cnt = 0;
761	          end
762	
763	          // Pop the W request
764	          void'(act_slv_port_w_queue.pop_front());
765	        end
766	      end
