1368	          void'(act_mst_port_ar_queue.pop_id(id));
1369	          mst_port_r_cnt[id] = 0;
1370	        end
1371	      end
1372	    endtask : mon_mst_port_r
1373	  endclass : axi_dw_downsizer_monitor
1374	
1375	endpackage: tb_axi_dw_pkg
